import React from 'react';

// ── Carte individuelle ────────────────────────────────────────────────────────
function MetricCard({ label, value, icon, color, description }) {
  const colors = {
    blue:   { bg: 'bg-blue-500/10',   border: 'border-blue-500/30',   text: 'text-blue-400',   bar: '#3b82f6' },
    green:  { bg: 'bg-green-500/10',  border: 'border-green-500/30',  text: 'text-green-400',  bar: '#10b981' },
    purple: { bg: 'bg-purple-500/10', border: 'border-purple-500/30', text: 'text-purple-400', bar: '#8b5cf6' },
    yellow: { bg: 'bg-yellow-500/10', border: 'border-yellow-500/30', text: 'text-yellow-400', bar: '#f59e0b' },
    pink:   { bg: 'bg-pink-500/10',   border: 'border-pink-500/30',   text: 'text-pink-400',   bar: '#ec4899' },
  };
  const c = colors[color] || colors.blue;

  return (
    <div className={`${c.bg} border ${c.border} rounded-xl p-4 space-y-2`}>
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <span className="text-base">{icon}</span>
          <span className="text-xs text-gray-400 font-semibold uppercase tracking-wider">{label}</span>
        </div>
        <span className={`text-xl font-black font-mono ${c.text}`}>
          {value != null ? `${value.toFixed(1)}%` : '—'}
        </span>
      </div>

      {/* Barre de progression */}
      <div className="h-1 bg-white/10 rounded-full overflow-hidden">
        <div
          className="h-full rounded-full transition-all duration-700"
          style={{ width: `${value ?? 0}%`, background: c.bar }}
        />
      </div>

      {description && (
        <p className="text-xs text-gray-500">{description}</p>
      )}
    </div>
  );
}

// ── Composant principal ───────────────────────────────────────────────────────
export default function MetricsCards({ results }) {
  if (!results || Object.keys(results).length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-12 text-gray-500">
        <span className="text-4xl mb-3">📊</span>
        <p className="text-sm font-semibold text-gray-400">Aucun modèle entraîné</p>
        <p className="text-xs mt-1">Entraînez un modèle pour voir les métriques</p>
      </div>
    );
  }

  const MODEL_NAMES = {
    logistic_regression: 'Logistic Regression',
    random_forest:       'Random Forest',
    svm:                 'SVM',
    knn:                 'KNN',
  };

  const MODEL_ICONS = {
    logistic_regression: '⚡',
    random_forest:       '🌲',
    svm:                 '🔷',
    knn:                 '🎯',
  };

  const METRICS = [
    { key: 'accuracy',  label: 'Accuracy',  icon: '🎯', color: 'blue',
      desc: 'Proportion globale de prédictions correctes' },
    { key: 'precision', label: 'Precision', icon: '🔬', color: 'green',
      desc: 'Parmi les prédits positifs, combien sont vrais' },
    { key: 'recall',    label: 'Recall',    icon: '🔍', color: 'yellow',
      desc: 'Parmi les vrais positifs, combien détectés' },
    { key: 'f1',        label: 'F1-Score',  icon: '⚖️', color: 'purple',
      desc: 'Moyenne harmonique Precision/Recall' },
    { key: 'roc_auc',   label: 'AUC-ROC',   icon: '📈', color: 'pink',
      desc: 'Capacité discriminante du modèle' },
  ];

  return (
    <div className="space-y-6">
      {Object.entries(results).map(([modelId, data]) => (
        <div key={modelId} className="space-y-3">

          {/* En-tête modèle */}
          <div className="flex items-center gap-2 pb-2 border-b border-white/8">
            <span className="text-lg">{MODEL_ICONS[modelId] || '🤖'}</span>
            <span className="font-bold text-sm text-white">
              {MODEL_NAMES[modelId] || modelId}
            </span>
            {data.roc_auc != null && (
              <span className="ml-auto text-xs px-2 py-0.5 rounded-full bg-blue-500/15 border border-blue-500/30 text-blue-400 font-mono">
                AUC {data.roc_auc.toFixed(1)}%
              </span>
            )}
          </div>

          {/* Grille des 5 métriques */}
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
            {METRICS.map(({ key, label, icon, color, desc }) => (
              <MetricCard
                key={key}
                label={label}
                value={data[key]}
                icon={icon}
                color={color}
                description={desc}
              />
            ))}
          </div>

        </div>
      ))}
    </div>
  );
}
